package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private Reader readerMock;

    @BeforeEach
    public void setUp() {
        readerMock = mock(Reader.class);
    }

    @Test
    public void testParseReturnsCSVParserInstance() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;

        // Use reflection to create a spy of CSVParser to verify constructor call
        Constructor<CSVParser> constructor = CSVParser.class.getDeclaredConstructor(Reader.class, CSVFormat.class);
        constructor.setAccessible(true);
        CSVParser parserSpy = spy(constructor.newInstance(readerMock, format));

        // Because we cannot mock construction, we test parse normally and verify type
        CSVParser parser = format.parse(readerMock);

        assertNotNull(parser);
        assertEquals(CSVParser.class, parser.getClass());
        // We cannot assertSame with parserSpy because parse creates a new instance internally
    }

    @Test
    public void testParseThrowsIOException() {
        CSVFormat format = CSVFormat.DEFAULT;

        // Create a Reader that throws IOException on read to simulate IOException during parsing
        Reader throwingReader = new Reader() {
            @Override
            public int read(char[] cbuf, int off, int len) throws IOException {
                throw new IOException("Mock IOException");
            }

            @Override
            public void close() throws IOException {
                // no-op
            }
        };

        assertThrows(IOException.class, () -> {
            format.parse(throwingReader);
        });
    }
}
